module top_module(
    input clk,
    input in,
    input reset,
    output reg out
);     // State Encoding
    parameter A = 0, B = 1;
    reg [1:0] X_state, next;

    // State Transition Logic
    always @(*) begin
        case (X_state)
            A: next = in ? B : A;
            B: next = in ? B : A;
        endcase
    end

    // State Register with synchronous Reset
    always @(posedge clk) begin
        if (reset) X_state <= B;
        else X_state <= next;
    end

    // Output Logic
    always @(*) begin
        case (X_state)
            A: out = 0;
            B: out = 0;
        endcase
    end
endmodule
